input.command:
export KUBECONFIG=/mydata/karma/runs/long-examples/elasticsearch-long-transform-scale-upgrade-20260617_130909/bundle/kubeconfig
PASS=$(kubectl get secret elastic-password -n elasticsearch -o jsonpath='{.data.password}' | base64 -d)

# Create the app-data index with routing to tier=new nodes
kubectl exec -n elasticsearch curl-test -- curl -sk -u "elastic:$PASS" \
  -X PUT "https://es-http:9200/app-data" \
  -H "Content-Type: application/json" \
  -d '{
    "settings": {
      "number_of_shards": 2,
      "number_of_replicas": 1,
      "index.routing.allocation.require.tier": "new"
    }
  }' 2>&1

